curl -s https://api.github.com/repos/rbenv/ruby-build/git/trees/HEAD?recursive=1 | python3 -c "
import sys, json
data = json.load(sys.stdin)
# Filter for share/ruby-build/ files which contain version definitions
versions = set()
for item in data.get('tree', []):
    path = item['path']
    if path.startswith('share/ruby-build/') and '/' not in path.replace('share/ruby-build/', '', 1):
        v = path.replace('share/ruby-build/', '')
        if v[0].isdigit():
            versions.add(v)
# Sort versions naturally
from packaging.version import Version
try:
    sorted_versions = sorted(versions, key=lambda v: Version(v), reverse=True)
    print('Top 20 latest Ruby versions:')
    for v in sorted_versions[:20]:
        print(v)
except:
    for v in sorted(versions, reverse=True)[:20]:
        print(v)
"

curl -s https://api.github.com/repos/rbenv/ruby-build/git/trees/HEAD?recursive=1 | python3 -c "
import sys, json, re
data = json.load(sys.stdin)
versions = set()
for item in data.get('tree', []):
    path = item['path']
    if path.startswith('share/ruby-build/') and '/' not in path.replace('share/ruby-build/', '', 1):
        v = path.replace('share/ruby-build/', '')
        if v and v[0].isdigit():
            versions.add(v)

# Natural sort using tuple of ints
def version_key(v):
    parts = re.split(r'[-.]', v)
    key = []
    for p in parts:
        try:
            key.append((0, int(p)))
        except ValueError:
            key.append((1, p))
    return tuple(key)

sorted_versions = sorted(versions, key=version_key, reverse=True)
print('Top 20 latest Ruby versions:')
for v in sorted_versions[:20]:
    print(v)
"

